mapper.select:
SELECT id, request_date, requested_by, target_team, status, remark, created_at
FROM packing_order
WHERE id = #{id}

SELECT COUNT(*)
FROM packing_order
WHERE status = #{status}

SELECT COUNT(*)
FROM packing_order
WHERE YEAR(request_date) = #{year}

SELECT COUNT(*)
FROM packing_order
WHERE YEAR(request_date) = #{year}
  AND QUARTER(request_date) = #{quarter}

SELECT COUNT(*)
FROM packing_order
WHERE YEAR(request_date) = #{year}
  AND QUARTER(request_date) = #{quarter}
  AND status IN ('READY_TO_SHIP', 'SHIPPED', 'RECEIVED', 'CANCELLED')

SELECT COUNT(*)
FROM packing_order
WHERE YEAR(request_date) = #{year}
  AND MONTH(request_date) = #{month}

SELECT COUNT(*)
FROM packing_order
WHERE YEAR(request_date) = #{year}
  AND MONTH(request_date) = #{month}
  AND status IN ('READY_TO_SHIP', 'SHIPPED', 'RECEIVED', 'CANCELLED')

SELECT COUNT(*)
FROM packing_order
WHERE YEAR(request_date) = #{year}
  AND WEEK(request_date, 1) = #{week}

SELECT COUNT(*)
FROM packing_order
WHERE YEAR(request_date) = #{year}
  AND WEEK(request_date, 1) = #{week}
  AND status IN ('READY_TO_SHIP', 'SHIPPED', 'RECEIVED', 'CANCELLED')

mapper.update:
UPDATE packing_order
SET status = #{status}
WHERE id = #{id}

UPDATE packing_order
SET completed_at = NOW()
WHERE id = #{id}

UPDATE packing_order
SET request_date = #{requestDate},
    status = #{status},
    remark = #{remark}
WHERE id = #{id}

